import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd"; // User input with malicious path traversal

        String basePath = "/var/www/data/"; // Base path for files

        String normalizedPath = new File(basePath).toPath().normalize().toString();
        String requestedFile = new File(normalizedPath, userInput).toString();

        if (!requestedFile.startsWith(normalizedPath)) {
            System.out.println("Invalid file path specified.");
            return;
        }

        try {
            File file = new File(requestedFile);
            FileInputStream fis = new FileInputStream(file);

            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }

            fis.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

